type OAuthSession = {
  provider: "google";
  accessToken: string;
  refreshToken: string;
  expiresAt: number;
  scopes: readonly ["profile", "email", "drive.readonly"];
};

type WorkerCommand =
  | { type: "oauth.exchange"; code: string; verifier: string }
  | { type: "oauth.refresh"; sessionId: string }
  | { type: "sync.enqueue"; resource: "workspace" | "file"; cursor?: string };

const extensionRuntime = {
  ui: "popup and command palette stay stateless",
  background: "owns PKCE exchange, refresh scheduling, retry backoff",
  storage: "encrypted OAuthSession envelope keyed by provider",
  invariant: "content scripts never receive refresh tokens"
} as const;

type FlowNode = {
  id: string;
  kind: "source" | "transform" | "ollama" | "sink";
  inputs: string[];
  outputs: string[];
};

const asfvPipeline = {
  runtime: "local-only",
  modelEndpoint: "http://127.0.0.1:11434/api/chat",
  stages: [
    { id: "source.scan", kind: "source", outputs: ["documents"] },
    { id: "chunk.semantic", kind: "transform", inputs: ["documents"], outputs: ["chunks"] },
    { id: "ollama.reason", kind: "ollama", inputs: ["chunks"], outputs: ["annotations"] },
    { id: "graph.persist", kind: "sink", inputs: ["annotations"], outputs: ["flowTrace"] }
  ] satisfies FlowNode[],
  invariant: "prompts and source payloads never leave localhost"
} as const;

const financeSchema = {
  presentation: "WinForms views bind to immutable view models",
  application: "TransactionService validates commands before persistence",
  domain: ["Account", "Category", "Transaction", "Budget"],
  infrastructure: {
    database: "SQLite",
    constraints: [
      "FOREIGN KEY(account_id) REFERENCES accounts(id)",
      "CHECK(amount > 0)",
      "UNIQUE(category_type, category_name)",
      "ON DELETE RESTRICT for transaction-owned rows"
    ]
  },
  invariant: "UI cannot write directly to SQLite repositories"
} as const;
